import{_ as r,c as t,o as e,a as _}from"./app.015fbf38.js";const m='{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E94\u7AE0","description":"","frontmatter":{"title":"\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E94\u7AE0","date":"2018-06-26T08:38:44.000Z","categories":["\u8B80\u7D93\u7D00\u9304"]},"headers":[],"relativePath":"Bike/BikeTravel/20180626_\u4F46\u4EE5\u7406\u66F8\u7B2C\u4E94\u7AE0.md","lastUpdated":1648513476165}',a={},p=_('<p><img src="https://farm2.staticflickr.com/1826/42284889245_9dfbe764da_k.jpg" alt=""><br></p><p>\u672C\u7AE0\u8A18\u8F09\u8457\u5DF4\u6BD4\u502B\u6700\u5F8C\u4E00\u500B\u738B\u4F2F\u6C99\u6492<br> \u4E3B\u8981\u89D2\u8272\u805A\u7126\u5728\u4F2F\u6C99\u6492\u8207\u4F46\u4EE5\u7406\u8EAB\u4E0A<br> \u63A8\u6E2C\u4F2F\u6C99\u6492\u738B\u662F\u525B\u610E\u81EA\u7528\u3001\u81BD\u5C0F\u7684\u4EBA<br> \u9019\u7BC7\u63ED\u9732\u5DF4\u6BD4\u502B\u5E1D\u570B\u7684\u6700\u5F8C\u4E00\u65E5<br> \u7576\u6642\u570B\u5BB6\u61C9\u8A72\u662F\u6230\u60C5\u544A\u6025\uFF0C\u8655\u65BC\u5371\u96E3<br> \u4F46\u570B\u738B\u53CD\u5176\u9053\u800C\u884C\uFF0C\u53CD\u800C\u98F2\u9152\u4F5C\u6A02<br> \u53EF\u80FD\u8981\u5B89\u64AB\u4EBA\u5FC3\uFF0C\u53E6\u4E00\u65B9\u9762\u9EBB\u75FA\u81EA\u5DF1<br> \u4F46\u5728\u5BB4\u6A02\u4E4B\u9918\uFF0C\u9084\u62FF\u51FA\u8056\u6BBF\u91D1\u9280\u5668\u76BF<br> \u4E00\u65B9\u9762\u70AB\u8000\u6230\u5229\u54C1\uFF0C\u4E00\u65B9\u9762\u662F\u91D1\u9444\u7684</p><p>\u7576\u738B\u770B\u898B\u7246\u4E0A\u51FA\u73FE\u6307\u982D\u5BEB\u5B57\u7684\u6642\u5019<br> \u738B\u5FC3\u610F\u9A5A\u60F6\uFF0C\u751A\u81F3\u96D9\u819D\u5F7C\u6B64\u76F8\u78B0<br> \u4E0D\u78BA\u5B9A\u662F\u5426\u64D4\u5FC3\u4FAE\u8511\u4EE5\u8272\u5217\u795E<br> \u7121\u610F\u4E2D\u8AA4\u89F8\u751A\u9EBC\u6A5F\u95DC\u5C0E\u81F4\u7570\u8C61\u767C\u751F<br><span style="color:blue;">(\u6709\u50CF\u96FB\u5F71\u76DC\u53D6\u57C3\u53CA\u6CD5\u8001\u7684\u5893<br> \u7D50\u679C\u6709\u795E\u79D8\u529B\u91CF\u51FA\u73FE\uFF0C\u80CC\u5F8C\u8FFD\u8457\u8DD1)</span><br> \u9019\u6642\u570B\u738B\u8A87\u4E0B\u6D77\u53E3\uFF0C\u53EA\u8981\u89E3\u51FA\u7246\u4E0A\u7684\u5B57<br> \u5C31\u80FD\u7ACB\u5373\u5750\u4E0A\u5169\u4EBA\u4E4B\u4E0B\uFF0C\u842C\u4EBA\u4E4B\u4E0A\u7684\u9AD8\u4F4D<br> (\u53E6\u5916\u4E00\u4F4D\u662F\u570B\u738B\u7684\u7236\u89AA)</p><p>\u570B\u4E2D\u7684\u8853\u58EB\u7686\u7121\u6CD5\u89E3\u7B54\u7246\u4E0A\u7684\u5B57<br> \u9019\u6642\u592A\u540E\u63D0\u8B70\u53EF\u627E\u5C0B\u4F46\u4EE5\u7406<br> (\u4F46\u4EE5\u7406\u53EF\u80FD\u4E0D\u53D7\u4EFB\u7528\uFF0C\u4E0D\u5728\u5BAE\u4E2D)<br> \u800C\u738B\u5C0D\u4F46\u4EE5\u7406\u7684\u614B\u5EA6\u8F15\u6162\uFF0C\u76F4\u547C\u88AB\u64C4...<br> \u4F60\u662F\u88AB\u64C4\u4E4B\u7336\u592A\u4EBA\u4E2D\u7684\u4F46\u4EE5\u7406\u55CE?</p><p>\u4F46\u4EE5\u7406\u4E0D\u53D7\u8A98\u60D1\uFF0C\u7518\u9858\u4E0D\u53D7\u797F\u89E3\u7246\u4E0A\u7684\u96E3\u5B57<br> \u614B\u5EA6\u4E5F\u8207\u5F9E\u524D\u7232\u5C3C\u5E03\u7532\u5C3C\u6492\u738B\u8B1B\u89E3\u4E0D\u540C<br> \u5148\u524D\u59D4\u5A49\u52F8\u8AAA\uFF0C\u5E0C\u671B\u738B\u80FD\u5920\u6094\u6539\u6B78\u6B63<br> \u9019\u6B21\u76F4\u63A5\u5BA3\u5E03\u5BE9\u5224\u7684\u8A0A\u606F\uFF0C\u5C07\u9762\u81E8\u4EA1\u570B</p><p>\u672C\u7AE0\u8F03\u70BA\u7279\u5225\u7684\u9EDE\uFF1A</p><p>\u5F85\u5B8C\u6210...</p>',7),s=[p];function b(o,c,i,n,d,l){return e(),t("div",null,s)}var T=r(a,[["render",b]]);export{m as __pageData,T as default};
